import json
import requests
from urllib.parse import urlparse

def lambda_handler(event, context):
    # Get the URL from the X-Enrich-URL header
    enrich_url = event['headers']['X-Enrich-URL']

    # Validate the URL to prevent malicious input
    if not urlparse(enrich_url).scheme:
        raise ValueError('Invalid URL')

    # Make an HTTP request to fetch the context data
    response = requests.get(enrich_url)

    # Parse the JSON response and extract the relevant data
    data = json.loads(response.text)
    context_data = {
        'context': data['context'],
        'metadata': data['metadata']
    }

    # Forward the request to the origin with the additional context data
    return {
        'statusCode': 200,
        'headers': {
            'Content-Type': 'application/json'
        },
        'body': json.dumps(context_data)
    }